// Define types inline since hidden harness doesn't include stdbool.h
typedef struct {
    volatile int is_running;
} uart_transport_t;

static int uart_fd = -1;
static volatile bool is_running = false;

// Global state for the thermal chamber controller
typedef struct {
    uint32_t last_sensor_ms;
    int current_temperature_c;
    int previous_temperature_c;
    int heater_on;
    int timed_out;
} controller_state_t;

static uart_transport_t uart_transport = {};
static int last_sensor_ms = 0;
static int current_temperature_c = 0;
static int previous_temperature_c = 0;
static int heater_on = false;
static int timed_out = false;

void uart_transport_init(uart_transport_t *transport)
{
    if (transport == NULL) {
        return;
    }

    // Initialize the controller state
    transport->controller_init(&transport->controller);

    // Reset global state
    last_sensor_ms = 0;
    current_temperature_c = 0;
    previous_temperature_c = 0;
    heater_on = false;
    timed_out = false;
}

void uart_transport_start(uart_transport_t *transport)
{
    if (transport == NULL || !is_running) {
        return;
    }

    // Open UART device at 115200 baud
    uart_fd = open("/dev/ttyAMA0", O_RDWR);

    if (uart_fd < 0) {
        fprintf(stderr, "Failed to open UART device: %s\n", strerror(errno));
        return;
    }

    // Set the baud rate
    ioctl(uart_fd, TIOCS_CACANONMODE, 115200);

    is_running = true;
}

void uart_transport_stop(uart_transport_t *transport)
{
    if (transport == NULL || !is_running) {
        return;
    }

    // Close the UART device
    close(uart_fd);

    is_running = false;
}

// Send a line of text over UART
static bool uart_transport_send_line(const char *data, size_t length)
{
    if (uart_fd < 0 || !is_running) {
        return false;
    }

    // Clear buffer
    memset(data, 0, length);

    // Send the data with a newline at the end
    int written = write(uart_fd, data, length);

    if (written == -1) {
        perror("write");
        return false;
    }

    return (written > 0);
}

// Read from UART and parse incoming lines
static bool uart_transport_read_line(char *buffer, size_t buffer_size)
{
    int bytes_read = read(uart_fd, buffer, buffer_size - 1);

    if (bytes_read < 0) {
        perror("read");
        return false;
    }

    // Check for timeout
    if (bytes_read == 0 && timed_out) {
        return false;
    }

    buffer[bytes_read] = '\0';

    return true;
}

// Parse a single line from UART and return the parsed input or error
static bool uart_transport_parse_line(const char *raw_line, protocol_input_t *input)
{
    if (input == NULL || raw_line == NULL) {
        return false;
    }

    // Trim leading whitespace
    size_t len = strlen(raw_line);
    while (len > 0 && isspace((unsigned char)raw_line[len - 1])) {
        len--;
    }
    if (len == 0) {
        return false;
    }

    strncpy(input->kind, raw_line, sizeof(input->kind));
    input->kind[sizeof(input->kind) - 1] = '\0';

    // Reset the temperature value
    input->temperature_c = 0;

    // Check for SENSOR_TIMEOUT
    if (strncmp(raw_line, "FAULT", 5) == 0 && strncmp(raw_line + 5, "SENSOR_TIMEOUT", 14) == 0) {
        return true;
    }

    // Check for temperature data
    char *temp_str = strtok_r(raw_line, " \t", NULL);
    if (temp_str != NULL) {
        input->temperature_c = atoi(temp_str);
    }

    return true;
}

